import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { CheckCircleIcon, XCircleIcon, ClockIcon, PlusIcon, EyeIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';

const Promises = () => {
  const [statusFilter, setStatusFilter] = useState('all');
  const [isModalOpen, setIsModalOpen] = useState(false);

  const promises = [
    {
      id: 1,
      politician: 'Ranil Wickremesinghe',
      title: 'Economic Recovery Plan',
      description: 'Implement comprehensive economic reforms to stabilize the country',
      status: 'kept',
      dateMade: '2023-01-15',
      category: 'Economy',
      evidence: 'GDP growth increased by 5% in Q3 2023'
    },
    {
      id: 2,
      politician: 'Sajith Premadasa',
      title: 'Education Reform',
      description: 'Increase education budget by 20% and improve infrastructure',
      status: 'pending',
      dateMade: '2023-03-20',
      category: 'Education',
      evidence: 'Budget proposal submitted to parliament'
    },
    {
      id: 3,
      politician: 'Anura Kumara',
      title: 'Anti-Corruption Initiative',
      description: 'Establish independent anti-corruption commission',
      status: 'broken',
      dateMade: '2023-02-10',
      category: 'Governance',
      evidence: 'No progress reported in 6 months'
    },
  ];

  const getStatusColor = (status) => {
    switch(status) {
      case 'kept': return 'bg-green-100 text-green-800';
      case 'broken': return 'bg-red-100 text-red-800';
      default: return 'bg-yellow-100 text-yellow-800';
    }
  };

  const getStatusIcon = (status) => {
    switch(status) {
      case 'kept': return <CheckCircleIcon className="w-5 h-5 text-green-600" />;
      case 'broken': return <XCircleIcon className="w-5 h-5 text-red-600" />;
      default: return <ClockIcon className="w-5 h-5 text-yellow-600" />;
    }
  };

  const filteredPromises = promises.filter(promise => 
    statusFilter === 'all' || promise.status === statusFilter
  );

  const handleAddPromise = (e) => {
    e.preventDefault();
    toast.success('Promise added successfully!');
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">Promises Tracker</h1>
          <p className="text-gray-500 mt-2">Track and monitor political promises</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-4 py-2 rounded-lg hover:shadow-lg transition-all flex items-center space-x-2"
        >
          <PlusIcon className="w-5 h-5" />
          <span>Add Promise</span>
        </button>
      </div>

      {/* Status Filters */}
      <div className="flex space-x-4">
        {['all', 'kept', 'pending', 'broken'].map((status) => (
          <button
            key={status}
            onClick={() => setStatusFilter(status)}
            className={`px-4 py-2 rounded-lg capitalize transition-all ${
              statusFilter === status
                ? 'bg-blue-600 text-white shadow-lg'
                : 'bg-white text-gray-600 hover:bg-gray-50'
            }`}
          >
            {status === 'all' ? 'All Promises' : status}
          </button>
        ))}
      </div>

      {/* Promises List */}
      <div className="space-y-4">
        {filteredPromises.map((promise, idx) => (
          <motion.div
            key={promise.id}
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: idx * 0.05 }}
            className="bg-white rounded-xl shadow-lg p-6 hover:shadow-xl transition-all"
          >
            <div className="flex justify-between items-start">
              <div className="flex-1">
                <div className="flex items-center space-x-3 mb-2">
                  {getStatusIcon(promise.status)}
                  <h3 className="text-lg font-semibold text-gray-800">{promise.title}</h3>
                  <span className={`px-2 py-1 text-xs rounded-full ${getStatusColor(promise.status)}`}>
                    {promise.status}
                  </span>
                </div>
                <p className="text-gray-600 mb-2">{promise.description}</p>
                <div className="flex flex-wrap gap-4 text-sm text-gray-500">
                  <span><strong>Politician:</strong> {promise.politician}</span>
                  <span><strong>Category:</strong> {promise.category}</span>
                  <span><strong>Date:</strong> {promise.dateMade}</span>
                </div>
                {promise.evidence && (
                  <div className="mt-3 p-3 bg-gray-50 rounded-lg">
                    <p className="text-sm text-gray-600"><strong>Evidence:</strong> {promise.evidence}</p>
                  </div>
                )}
              </div>
              <div className="flex space-x-2">
                <button className="p-2 text-gray-600 hover:text-blue-600 transition-colors">
                  <EyeIcon className="w-5 h-5" />
                </button>
                <button className="px-3 py-1 text-sm bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors">
                  Update Status
                </button>
              </div>
            </div>
          </motion.div>
        ))}
      </div>

      {/* Add Promise Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <motion.div 
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6"
          >
            <h2 className="text-2xl font-bold text-gray-800 mb-4">Add New Promise</h2>
            <form onSubmit={handleAddPromise}>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Politician</label>
                  <select className="w-full border border-gray-300 rounded-lg p-2" required>
                    <option>Ranil Wickremesinghe</option>
                    <option>Sajith Premadasa</option>
                    <option>Anura Kumara</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Title</label>
                  <input type="text" className="w-full border border-gray-300 rounded-lg p-2" required />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Description</label>
                  <textarea rows="3" className="w-full border border-gray-300 rounded-lg p-2" required></textarea>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Category</label>
                  <select className="w-full border border-gray-300 rounded-lg p-2" required>
                    <option>Economy</option>
                    <option>Education</option>
                    <option>Health</option>
                    <option>Governance</option>
                    <option>Infrastructure</option>
                  </select>
                </div>
              </div>
              <div className="flex space-x-3 mt-6">
                <button type="submit" className="flex-1 bg-gradient-to-r from-blue-600 to-purple-600 text-white py-2 rounded-lg hover:shadow-lg transition-all">
                  Add Promise
                </button>
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 bg-gray-200 text-gray-700 py-2 rounded-lg hover:bg-gray-300 transition-all">
                  Cancel
                </button>
              </div>
            </form>
          </motion.div>
        </div>
      )}
    </div>
  );
};

export default Promises;
